if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];

const body = $input.first().json.body || $input.first().json;
// Health/ping bypass
const action = body.action || '';
if (action === 'ping' || action === 'health' || action === 'status') {
  return [{json: {status: 'ok', module: 'pptx-gen', action: action, timestamp: new Date().toISOString(), _bypass: true}}];
}
const topic = body.topic || body.template_type || body.type || body.title || null;
const slides_data = body.slides_data || null;
if (!topic && !slides_data) {
  throw new Error('Missing required field: provide topic, template_type, type, title, or slides_data');
}
const sessionId = body.session_id || 'pptx_' + Date.now();
return [{ json: {
  session_id: sessionId, topic: topic, slides_data: slides_data,
  title: body.title || topic || 'GDA Analysis Report',
  agency: body.agency || 'GDA',
  audience: body.audience || 'Executive Leadership',
  key_points: Array.isArray(body.key_points) ? body.key_points.join(', ') : (body.key_points || body.keyPoints || ''),
  slide_count: body.slide_count || body.slideCount || body.slides || 10,
  theme: body.theme || body.style || 'Professional Dark',
  include_charts: body.include_charts !== false,
  include_executive_summary: body.include_executive_summary !== false,
  classification: body.classification || 'UNCLASSIFIED',
  callback_url: body.callback_url || null
} }];

const validated = $('Validate PPTX Input').first().json;
const tavily = $input.first().json;
let research = '';
try {
  if (tavily.answer) research += 'RESEARCH SUMMARY:\n' + tavily.answer + '\n\n';
  if (tavily.results && tavily.results.length > 0) {
    research += 'KEY SOURCES:\n';
    tavily.results.forEach((r, i) => {
      research += (i+1) + '. ' + (r.title || '') + '\n   ' + (r.content || '').substring(0, 400) + '\n   Source: ' + (r.url || '') + '\n\n';
    });
  }
} catch(e) {
  research = 'Web research unavailable. Generate slides from general knowledge.';
}
return [{ json: { ...validated, research } }];

const claudeResp = $input.first().json;
const raw = claudeResp.content && claudeResp.content[0] ? claudeResp.content[0].text || '' : '';
const validated = $('Merge Research').first().json;
let slides = [];
try {
  const clean = raw.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim();
  slides = JSON.parse(clean).slides || [];
} catch(e) {
  const match = raw.match(/\{[\s\S]*\}/);
  if (match) { try { slides = JSON.parse(match[0]).slides || []; } catch(e2) {} }
}
if (slides.length === 0 && validated.slides_data) {
  slides = validated.slides_data;
}
return [{ json: { ...validated, slides } }];

const slides = $input.first().json.slides || [];
const title = $input.first().json.title || 'GDA Analysis Report';
const agency = $input.first().json.agency || 'GDA';
const session_id = $input.first().json.session_id || 'pptx_' + Date.now();
const date = new Date().toLocaleDateString('en-US', {month:'long',day:'numeric',year:'numeric'});
const GOLD='#C8A84B', NAVY='#1B3A6B';
let html = '<!DOCTYPE html><html><head><meta charset="UTF-8"><title>' + title + '</title><style>*{box-sizing:border-box;margin:0;padding:0}body{font-family:Calibri,Arial,sans-serif;background:' + NAVY + '}.slide{width:1280px;min-height:720px;background:white;margin:10px auto;padding:60px 70px 50px;page-break-after:always;position:relative}.class-bar{position:absolute;top:0;left:0;right:0;background:#1a6b1a;color:white;text-align:center;padding:4px;font-weight:bold;font-size:13px;letter-spacing:2px}.slide-num{position:absolute;bottom:15px;right:25px;color:#999;font-size:13px}.footer{position:absolute;bottom:15px;left:70px;color:#999;font-size:13px}.title-slide{background:linear-gradient(135deg,' + NAVY + ' 0%,#0d2247 100%);color:white;display:flex;flex-direction:column;justify-content:center;align-items:center;text-align:center}.main-title{font-size:48px;font-weight:bold;color:' + GOLD + ';margin-bottom:20px}.subtitle{font-size:22px;color:#fff}.meta{font-size:16px;color:#aab8cc;margin-top:20px}.title-slide .slide-num,.title-slide .footer{color:rgba(255,255,255,0.4)}.slide-title{color:' + NAVY + ';font-size:34px;font-weight:bold;padding-top:20px;border-bottom:3px solid ' + GOLD + ';padding-bottom:12px;margin-bottom:30px}.bullets{list-style:none;padding-left:0}.bullets li{font-size:20px;color:#222;line-height:1.6;padding:8px 0 8px 30px;position:relative;border-bottom:1px solid #f0f0f0}.bullets li:before{content:"\u25B8";color:' + GOLD + ';position:absolute;left:0;top:11px;font-size:16px}</style></head><body>';
html += '<div class="slide title-slide"><div class="class-bar">UNCLASSIFIED</div><div style="margin-top:40px"><div class="main-title">' + title + '</div><div class="subtitle">' + agency + '</div><div class="meta">Generated by GDA Command | ' + date + '</div></div><div class="footer">UNCLASSIFIED</div><div class="slide-num">1 / ' + (slides.length+1) + '</div></div>';
slides.forEach(function(slide, i) {
  var bullets = (slide.bullets || []).map(function(b) { return '<li>' + b + '</li>'; }).join('');
  html += '<div class="slide"><div class="class-bar">UNCLASSIFIED</div><div class="slide-title">' + (slide.title || 'Slide ' + (i+2)) + '</div><ul class="bullets">' + bullets + '</ul><div class="footer">' + title + ' | ' + agency + '</div><div class="slide-num">' + (i+2) + ' / ' + (slides.length+1) + '</div></div>';
});
html += '</body></html>';
var file_base64 = Buffer.from(html).toString('base64');
return [{ json: { download_url: 'data:text/html;base64,' + file_base64, file_name: title.replace(/[^a-zA-Z0-9]/g, '_') + '.html', slide_count: slides.length + 1, session_id: session_id, status: 'complete', format: 'html_presentation', slides: slides } }];
